# Dəyişməzlik nümunəsi
numbers = (1, 2, 3)
try:
    numbers[0] = 10
except TypeError:
    print('Xəta: Tuple elementləri dəyişdirilə bilməz!')

// TypeScript kodu
const coords: [number, number] = [10, 20];
console.log(coords);

# Səhv idarəetməsi
numbers = (1, 2, 3)
try:
    print(numbers[10])
except IndexError:
    print('Xəta: İndeks tuple-dan kənardır!')

try:
    numbers[0] = 10
except TypeError:
    print('Xəta: Tuple elementləri dəyişdirilə bilməz!')

# Immutability example
numbers = (1, 2, 3)
try:
    numbers[0] = 10
except TypeError:
    print('Error: Tuple elements cannot be modified!')

// TypeScript code
const coords: [number, number] = [10, 20];
console.log(coords);

# Error handling
numbers = (1, 2, 3)
try:
    print(numbers[10])
except IndexError:
    print('Error: Index out of range!')

try:
    numbers[0] = 10
except TypeError:
    print('Error: Tuple elements cannot be modified!')

# Пример неизменяемости
numbers = (1, 2, 3)
try:
    numbers[0] = 10
except TypeError:
    print('Ошибка: Элементы кортежа нельзя изменить!')

// Код TypeScript
const coords: [number, number] = [10, 20];
console.log(coords);

# Обработка ошибок
numbers = (1, 2, 3)
try:
    print(numbers[10])
except IndexError:
    print('Ошибка: Индекс вне диапазона!')

try:
    numbers[0] = 10
except TypeError:
    print('Ошибка: Элементы кортежа нельзя изменить!')
